  1→use askama::Template;
  2→use axum::extract::{Path, State};
  3→use axum::http::{HeaderMap, StatusCode};
  4→use axum::response::{Html, IntoResponse, Redirect, Response};
  5→use axum::Form;
  6→use sqlx::PgPool;
  7→use uuid::Uuid;
  8→
  9→use super::auth::AuthenticatedUser;
 10→use crate::domain::{TodoItem, TodoItemId};
 11→use crate::services::todo_service::{
 12→    add_todo, delete_todo, get_todos, toggle_todo_completion, update_todo_title, AddTodoError,
 13→    DeleteTodoError, ToggleTodoError, UpdateTitleError,
 14→};
 15→
 16→fn is_htmx_request(headers: &HeaderMap) -> bool {
 17→    headers.contains_key("hx-request")
 18→}
 19→
 20→/// Build an HTMX response with an HX-Trigger header that fires an "announce" event
 21→/// for screen reader live regions.
 22→fn htmx_response_with_announce(body: Html<String>, message: &str) -> Response {
 23→    let trigger_json = format!(r#"{{"announce":"{}"}}"#, message);
 24→    (
 25→        [(
 26→            axum::http::header::HeaderName::from_static("hx-trigger"),
 27→            axum::http::HeaderValue::from_str(&trigger_json).unwrap(),
 28→        )],
 29→        body,
 30→    )
 31→        .into_response()
 32→}
 33→
 34→/// View model for a single todo item in the template.
 35→pub struct TodoItemView {
 36→    pub id: String,
 37→    pub title: String,
 38→    pub is_completed: bool,
 39→}
 40→
 41→impl From<&TodoItem> for TodoItemView {
 42→    fn from(item: &TodoItem) -> Self {
 43→        Self {
 44→            id: item.id().as_uuid().to_string(),
 45→            title: item.title().as_str().to_string(),
 46→            is_completed: item.is_completed(),
 47→        }
 48→    }
 49→}
 50→
 51→#[derive(Template)]
 52→#[template(path = "todos.html")]
 53→pub struct TodosTemplate {
 54→    pub todos: Vec<TodoItemView>,
 55→    pub error_message: Option<String>,
 56→}
 57→
 58→#[derive(Template)]
 59→#[template(path = "todo_item.html")]
 60→pub struct TodoItemTemplate {
 61→    pub todo: TodoItemView,
 62→}
 63→
 64→pub async fn get_todos_page(
 65→    AuthenticatedUser(user_id): AuthenticatedUser,
 66→    State(pool): State<PgPool>,
 67→) -> Result<impl IntoResponse, TodosError> {
 68→    let todos = get_todos(&pool, &user_id)
 69→        .await
 70→        .map_err(TodosError::Unexpected)?;
 71→
 72→    let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();
 73→
 74→    let template = TodosTemplate {
 75→        todos: todo_views,
 76→        error_message: None,
 77→    };
 78→    Ok(Html(template.render()?))
 79→}
 80→
 81→#[derive(serde::Deserialize)]
 82→pub struct AddTodoForm {
 83→    pub title: String,
 84→}
 85→
 86→pub async fn post_todo(
 87→    AuthenticatedUser(user_id): AuthenticatedUser,
 88→    State(pool): State<PgPool>,
 89→    headers: HeaderMap,
 90→    Form(form): Form<AddTodoForm>,
 91→) -> Result<Response, TodosError> {
 92→    let htmx = is_htmx_request(&headers);
 93→
 94→    // Silently ignore empty/whitespace-only submissions per US-5
 95→    if form.title.trim().is_empty() {
 96→        if htmx {
 97→            return Ok(StatusCode::NO_CONTENT.into_response());
 98→        }
 99→        return Ok(Redirect::to("/todos").into_response());
100→    }
101→
102→    match add_todo(&pool, user_id.clone(), form.title).await {
103→        Ok(item) => {
104→            if htmx {
105→                let template = TodoItemTemplate {
106→                    todo: TodoItemView::from(&item),
107→                };
108→                let body = template.render().map_err(TodosError::Render)?;
109→                Ok(htmx_response_with_announce(Html(body), "Todo added"))
110→            } else {
111→                Ok(Redirect::to("/todos").into_response())
112→            }
113→        }
114→        Err(AddTodoError::InvalidTitle(title_err)) => {
115→            let user_facing = match title_err {
116→                crate::domain::TodoTitleError::Empty => {
117→                    // Should not reach here due to empty check above, but handle gracefully
118→                    if htmx {
119→                        return Ok(StatusCode::NO_CONTENT.into_response());
120→                    }
121→                    return Ok(Redirect::to("/todos").into_response());
122→                }
123→                crate::domain::TodoTitleError::TooLong { max, .. } => {
124→                    format!("That title is too long (max {max} characters)")
125→                }
126→            };
127→
128→            let todos = get_todos(&pool, &user_id)
129→                .await
130→                .map_err(TodosError::Unexpected)?;
131→            let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();
132→
133→            let template = TodosTemplate {
134→                todos: todo_views,
135→                error_message: Some(user_facing),
136→            };
137→            let body = template.render().map_err(TodosError::Render)?;
138→            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
139→        }
140→        Err(AddTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
141→    }
142→}
143→
144→pub async fn post_toggle_todo(
145→    AuthenticatedUser(user_id): AuthenticatedUser,
146→    State(pool): State<PgPool>,
147→    headers: HeaderMap,
148→    Path(todo_id): Path<Uuid>,
149→) -> Result<Response, TodosError> {
150→    let htmx = is_htmx_request(&headers);
151→    let todo_item_id = TodoItemId::from_uuid(todo_id);
152→
153→    match toggle_todo_completion(&pool, &todo_item_id, &user_id).await {
154→        Ok(toggled) => {
155→            if htmx {
156→                let announce = if toggled.is_completed() {
157→                    "Todo completed"
158→                } else {
159→                    "Todo marked pending"
160→                };
161→                let template = TodoItemTemplate {
162→                    todo: TodoItemView::from(&toggled),
163→                };
164→                let body = template.render().map_err(TodosError::Render)?;
165→                Ok(htmx_response_with_announce(Html(body), announce))
166→            } else {
167→                Ok(Redirect::to("/todos").into_response())
168→            }
169→        }
170→        Err(ToggleTodoError::NotFound) => Ok((
171→            StatusCode::NOT_FOUND,
172→            Html("<h1>Todo not found</h1>".to_string()),
173→        )
174→            .into_response()),
175→        Err(ToggleTodoError::Unauthorized) => Ok((
176→            StatusCode::FORBIDDEN,
177→            Html("<h1>Not authorized</h1>".to_string()),
178→        )
179→            .into_response()),
180→        Err(ToggleTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
181→    }
182→}
183→
184→pub async fn post_delete_todo(
185→    AuthenticatedUser(user_id): AuthenticatedUser,
186→    State(pool): State<PgPool>,
187→    headers: HeaderMap,
188→    Path(todo_id): Path<Uuid>,
189→) -> Result<Response, TodosError> {
190→    let htmx = is_htmx_request(&headers);
191→    let todo_item_id = TodoItemId::from_uuid(todo_id);
192→
193→    match delete_todo(&pool, &todo_item_id, &user_id).await {
194→        Ok(()) => {
195→            if htmx {
196→                Ok(htmx_response_with_announce(
197→                    Html(String::new()),
198→                    "Todo deleted",
199→                ))
200→            } else {
201→                Ok(Redirect::to("/todos").into_response())
202→            }
203→        }
204→        Err(DeleteTodoError::NotFound) => Ok((
205→            StatusCode::NOT_FOUND,
206→            Html("<h1>Todo not found</h1>".to_string()),
207→        )
208→            .into_response()),
209→        Err(DeleteTodoError::Unauthorized) => Ok((
210→            StatusCode::FORBIDDEN,
211→            Html("<h1>Not authorized</h1>".to_string()),
212→        )
213→            .into_response()),
214→        Err(DeleteTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
215→    }
216→}
